import axios from 'axios';
import {
    ADD_TO_CART_USER,
} from './types';

const url="/api/auth/addToCart?productId=${_id}"
export function addToCart(_id) {
    const request = axios.post(url)
        .then(response => response.data);

    return {
        type: ADD_TO_CART_USER,
        payload: request
    }
}
